parts.text:
=Analise esta transação financeira e retorne um JSON.

Descrição: {{ $json.body.description }}
Categoria sugerida: {{ $json.body.category }}
Tipo: {{ $json.body.type }}
Valor: R$ {{ $json.body.amount }}

Regras:
- Confirme ou corrija a categoria para uma destas: Salário, Freelance, Alimentação, Moradia, Transporte, Saúde, Educação, Lazer, Outros
- Determine se é gasto ESSENCIAL (necessidade básica: alimentação, moradia, saúde, transporte, educação) ou SUPÉRFLUO (lazer, luxo, entretenimento)
- Entradas (salário, freelance) são sempre essential: false

Responda APENAS com JSON válido: {"category": "NomeCategoria", "essential": true}

parameters.jsCode:
const text = $input.item.json.candidates[0].content.parts[0].text;
let category = $('Webhook').item.json.body.category || 'Outros';
let essential = false;
try {
  const cleaned = text.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  category = parsed.category || category;
  essential = parsed.essential === true;
} catch(e) {}

const body = $('Webhook').item.json.body;
return [{ json: {
  transaction_id: body.transaction_id,
  user_id: body.user_id,
  amount: parseFloat(body.amount),
  type: body.type,
  category,
  essential
}}];

const totais = $('Calcular Totais do Mês').item.json;
const perfil = $('Buscar Perfil').item.json;
const classif = $('Extrair Classificação').item.json;

const renda = parseFloat(totais.renda);
const gastos_essenciais = parseFloat(totais.gastos_essenciais);
const total_gastos = parseFloat(totais.total_gastos);
const saldo_restante = renda - total_gastos;
const percentual_gasto = renda > 0 ? Math.round((total_gastos / renda) * 100) : 0;
const monthly_limit = parseFloat(perfil.monthly_limit) || 0;
const limite_percentual = monthly_limit > 0 ? monthly_limit : renda * 0.8;

return [{ json: {
  renda,
  gastos_essenciais,
  total_gastos,
  saldo_restante,
  percentual_gasto,
  category: classif.category,
  essential: classif.essential,
  alerta: total_gastos >= limite_percentual && perfil.whatsapp,
  whatsapp: perfil.whatsapp,
  monthly_limit: limite_percentual
}}];

const d = $input.item.json;
const mes = new Date().toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });
const fmt = v => `R$ ${parseFloat(v).toFixed(2).replace('.', ',')}` ;

const msg = `⚠️ *Alerta Finanças Pessoais*

Você já gastou *${fmt(d.total_gastos)}* de *${fmt(d.renda)}* (${d.percentual_gasto}%)

💰 Gastos essenciais: *${fmt(d.gastos_essenciais)}*
💳 Saldo restante: *${fmt(d.saldo_restante)}*

Cuidado com os gastos este mês! 💪`;

return [{ json: { whatsapp: d.whatsapp, message: msg } }];
